# variables.tf
variable "azs" {
  default = ["us-east-1a", "us-east-1b", "us-east-1c"]
}

# main.tf
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = { Name = "prod-vpc" }
}

resource "aws_subnet" "public" {
  count             = length(var.azs)
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = var.azs[count.index]
  map_public_ip_on_launch = true
  tags = { Name = "public-${var.azs[count.index]}", Tier = "public" }
}

resource "aws_subnet" "private" {
  count             = length(var.azs)
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 10}.0/24"
  availability_zone = var.azs[count.index]
  tags = { Name = "private-${var.azs[count.index]}", Tier = "app" }
}

resource "aws_subnet" "isolated" {
  count             = length(var.azs)
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 20}.0/24"
  availability_zone = var.azs[count.index]
  tags = { Name = "isolated-${var.azs[count.index]}", Tier = "db" }
}

resource "aws_eip" "nat" {
  count  = length(var.azs)
  domain = "vpc"
}

resource "aws_nat_gateway" "main" {
  count         = length(var.azs)
  allocation_id = aws_eip.nat[count.index].id
  subnet_id     = aws_subnet.public[count.index].id
  tags = { Name = "nat-${var.azs[count.index]}" }
}

resource "aws_route_table" "private" {
  count  = length(var.azs)
  vpc_id = aws_vpc.main.id
  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main[count.index].id
  }
  tags = { Name = "private-rt-${var.azs[count.index]}" }
}

resource "aws_route_table_association" "private" {
  count          = length(var.azs)
  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private[count.index].id
}

# FIS experiment template for EC2 AZ termination (staging only)
cat > /tmp/fis-multiaz-test.json << 'EOF'
{
  "description": "Terminate all app-tier instances in us-east-1a (staging)",
  "targets": {
    "app-instances-1a": {
      "resourceType": "aws:ec2:instance",
      "resourceTags": {"Env": "staging", "Tier": "app"},
      "filters": [{"path": "Placement.AvailabilityZone", "values": ["us-east-1a"]}],
      "selectionMode": "ALL"
    }
  },
  "actions": {
    "terminate-app-1a": {
      "actionId": "aws:ec2:terminate-instances",
      "targets": {"Instances": "app-instances-1a"}
    }
  },
  "stopConditions": [
    {"source": "aws:cloudwatch:alarm",
     "value": "arn:aws:cloudwatch:us-east-1:123456789012:alarm:staging-error-rate"}
  ],
  "roleArn": "arn:aws:iam::123456789012:role/FISRole"
}
EOF

TMPL=$(aws fis create-experiment-template \
  --cli-input-json file:///tmp/fis-multiaz-test.json \
  --query 'experimentTemplate.id' --output text)

aws fis start-experiment --experiment-template-id "$TMPL" \
  --query 'experiment.{Id:id,State:state}'
